import { ActionPageDetailFormValues } from '@domain/actionPages';
import { PublicActionPage } from '@domain/publicActionPage';
import { useCallback, useEffect, useMemo } from 'react';
import { useFormContext, useWatch } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import {
  BriefcaseIcon,
  ContactIcon,
  NetworkIcon,
} from 'src/builder/PublicActionPage/components/icons';
import { MultiSwitch } from 'src/builder/PublicActionPage/components/MultiSwitch';

type Props = {
  actionPage?: PublicActionPage;
  includeOrganization?: boolean;
};

export const MakeDonationAsSelector = ({ actionPage, includeOrganization }: Props) => {
  const { t } = useTranslation('customFields');
  const { setValue } = useFormContext();
  const makeDonationAs = useWatch({ name: 'makeDonationAs' });

  const formOrganizationLabels = useWatch<
    ActionPageDetailFormValues,
    'fieldConfiguration.organizationLabels'
  >({
    name: 'fieldConfiguration.organizationLabels',
  });

  const organizationLabels = useMemo(
    () => actionPage?.fieldConfiguration?.organizationLabels || formOrganizationLabels,
    [actionPage?.fieldConfiguration?.organizationLabels, formOrganizationLabels]
  );

  const options = useMemo(() => {
    const opts = [
      {
        label: (
          <div className="flex items-center justify-center gap-2">
            <ContactIcon className="@xs:inline-block hidden w-[15px]" />
            {t('name.individual')}
          </div>
        ),
        value: 'individual',
      },
    ];

    if (includeOrganization) {
      if (
        !organizationLabels ||
        organizationLabels.includes('business') ||
        organizationLabels.includes('organization')
      ) {
        const useBusiness = organizationLabels?.includes('business');
        opts.push({
          label: (
            <div className="flex items-center justify-center gap-2">
              <BriefcaseIcon className="@xs:inline-block hidden w-[15px]" />
              {useBusiness ? t('name.business') : t('name.organization')}
            </div>
          ),
          value: useBusiness ? 'business' : 'organization',
        });
      }
    }

    if (organizationLabels?.includes('pac')) {
      opts.push({
        label: (
          <div className="flex items-center justify-center gap-2">
            <NetworkIcon className="@xs:inline-block hidden w-[15px]" />
            {t('name.pac')}
          </div>
        ),
        value: 'pac',
      });
    }

    return opts;
  }, [t, includeOrganization, organizationLabels]);

  const selectedOption = useMemo(
    () => options.findIndex((opt) => opt.value === makeDonationAs),
    [makeDonationAs, options]
  );

  const setSelectedOption = useCallback(
    (idx: number) => setValue('makeDonationAs', options[idx]?.value, { shouldValidate: true }),
    [options, setValue]
  );

  useEffect(() => {
    if (options.findIndex((opt) => opt.value === makeDonationAs) === -1) {
      setValue('makeDonationAs', options[0]?.value, { shouldValidate: true });
    }
  }, [makeDonationAs, options, setValue]);

  return options.length > 1 ? (
    <MultiSwitch
      className="w-full @container/multiSwitch"
      options={options}
      selectedOption={selectedOption}
      setSelectedOption={setSelectedOption}
      variant="grayscale"
    />
  ) : null;
};

